+                match v {
+                    rustls::ProtocolVersion::TLSv1_2 => 0x0303,
+                    rustls::ProtocolVersion::TLSv1_3 => 0x0304,
+                    // For unknown versions, use a high value so they're excluded by default
+                    _ => 0xFFFF,
+                }
+            }
